import 'bootstrap/dist/css/bootstrap.min.css';
import './css/home.css'

import photo from './img/gatito.jpg'

export default function Home(){
    return (
        <div className="Home">
                <section className='main-page' id='main-page-id'>
                    <div className='container d-flex align-items-center justify-content-center'>
                        <div className='text-main-page'>
                            <div className='col-md-12'>
                                <img  className='pfp' src={photo} width={200} height={200} alt='pfp-photo'/>
                                <p className='name'>Jorge <span className='name-p1'>Alexis</span> <span className='name-p1'>M</span>árquez <span className='name-p1'>Rosales</span></p>  
                            </div>
                            <div className='container text-center main-text'>
                                <p>Lorem ipsum dolor sit amet, consectetur adipiscing elit. Morbi faucibus ut dui commodo aliquam. Duis non ipsum posuere, viverra lorem pellentesque, semper elit. Proin pellentesque, mi</p>
                            </div>
                        </div>
                    </div>
                </section>
                <section className='projects-page'>
                    <div className='container'>
                        <div className='row'>
                            <div className='col-md-12'>

                            </div>
                        </div>
                    </div>
                </section>
        </div>
    )
}

window.addEventListener('scroll', function() {
    var nav = document.querySelector('.nav');
    var section = document.querySelector('#main-page-id');
    if (window.scrollY >= section.offsetTop + section.offsetHeight) {
      nav.classList.add('shadow');
    } else {
      nav.classList.remove('shadow');
    }
});
